#include<bits/stdc++.h>
using namespace std;
long long a[200010];
const long long inf=(1ll<<30);
int main()
{
    int n,q;
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    while(q--)
    {
        int op;
        scanf("%d",&op);
        if(op==1)
        {
            long long x,y;
            scanf("%lld%lld",&x,&y);
            a[x]=y;
        }
        else
        {
            int x,y;
            scanf("%d%d",&x,&y);
            if(y-x>80)
            {
                printf("Too large\n");
                continue;
            }
            __int128 ans=1;
            for(int i=x;i<=y;i++)
            {
                __int128 sum=1;
                for(int j=i;j<=y;j++)
                {
                    sum*=a[j];
                    ans=max(ans,sum);
                    if(ans>inf)
                    {
                        break;
                    }
                }
                if(ans>inf)
                {
                    break;
                }
            }
            if(ans>inf)
            {
                printf("Too large\n");
            }
            else
            {
                printf("%lld\n",(long long)(ans));
            }
        }
    }
    return 0;
}
